-- Case 01: relational + semi-structured + analytical syntax.
With Recursive source_rows As (select column1::NUMBER As event_id, column2::TIMESTAMP_TZ As event_time, PARSE_JSON(column3) As payload From Values (1, '2026-06-01 09:00:00 +09:00', '{"customer":{"id":"C001","name":"杉野尾 広貴","locale":"ja-JP"},"items":[{"sku":"本-001","qty":2,"price":1200.50},{"sku":"茶-002","qty":1,"price":850}],"flags":{"gift":true,"priority":"高"}}'), (2, '2026-06-01 12:30:00 +02:00', '{"customer":{"id":"C002","name":"Élodie d''Arcy","locale":"fr-FR"},"items":[{"sku":"CAFÉ-01","qty":3,"price":4.75}],"flags":{"gift":false,"priority":"normal"}}')), flattened_items As (select s.event_id, s.event_time, s.payload:customer.id::STRING As customer_id, s.payload:customer.name::STRING As customer_name, s.payload:customer.locale::STRING As locale, item.index as item_index, item.value:sku::STRING as sku, item.value:qty::NUMBER as quantity, item.value:price::NUMBER(18, 2) as unit_price, quantity * unit_price As line_amount, COALESCE(s.payload:flags.gift::BOOLEAN, false) As is_gift, s.payload:flags.priority::STRING As priority From source_rows As s, lateral FLATTEN(INPUT => s.payload:items, outer => True, recursive => False, MODE => 'ARRAY') as item), ranked_items as (Select *, ROW_NUMBER() over (Partition By customer_id Order By line_amount Desc, event_time desc, item_index) as value_rank, SUM(line_amount) over (Partition By customer_id Order By event_time, item_index rows between UNBOUNDED PRECEDING and current row) As running_amount, RATIO_TO_REPORT(line_amount) Over (partition by customer_id) As amount_ratio From flattened_items Qualify value_rank <= 10), org_tree(employee_id, manager_id, depth, path) as (Select employee_id, manager_id, 0 As depth, ARRAY_CONSTRUCT(employee_id) As path From CORE.EMPLOYEES Where manager_id Is Null Union All Select child.employee_id, child.manager_id, parent.depth + 1, ARRAY_APPEND(parent.path, child.employee_id) from CORE.EMPLOYEES as child inner join org_tree as parent on child.manager_id = parent.employee_id where not ARRAY_CONTAINS(child.employee_id::Variant, parent.path)) select r.customer_id, MAX(r.customer_name) as customer_name, MAX(r.locale) as locale, COUNT_IF(r.quantity > 0) as valid_line_count, SUM(r.quantity) as total_quantity, ROUND(SUM(r.line_amount), 2) as gross_amount, ARRAY_AGG(OBJECT_CONSTRUCT_KEEP_NULL('sku', r.sku, 'quantity', r.quantity, 'amount', r.line_amount, 'rank', r.value_rank, 'ratio', r.amount_ratio)) Within Group (order by r.value_rank) As ranked_lines, OBJECT_AGG(r.sku, r.line_amount) as amount_by_sku, LISTAGG(Distinct r.priority, ' | ') Within Group (order by r.priority) As priorities From ranked_items As r Where r.customer_name Ilike Any ('%杉%', '%élodie%', '%홍%') or r.locale in ('ja-JP', 'fr-FR', 'ko-KR', 'ar-SA') Group By GROUPING SETS ((r.customer_id), ()) Having SUM(r.line_amount) >= 0 Order By GROUPING(r.customer_id), gross_amount Desc Nulls LAST;
select order_id, match_number, started_at, completed_at, DATEDIFF('minute', started_at, completed_at) as elapsed_minutes from CORE.ORDER_STATUS_HISTORY match_recognize (Partition By order_id Order By status_at Measures MATCH_NUMBER() As match_number, FIRST(created.status_at) As started_at, LAST(delivered.status_at) As completed_at One Row PER MATCH After MATCH SKIP PAST LAST Row Pattern (created+ paid+ shipped* delivered) DEFINE created as created.status = 'CREATED', paid As paid.status = 'PAID', shipped As shipped.status = 'SHIPPED', delivered as delivered.status = 'DELIVERED');
select * from (Select region, locale, net_amount From MART.ORDER_FACTS Where order_date >= DATEADD('day', -30, CURRENT_DATE())) Pivot (SUM(net_amount) For locale In ('ja-JP' as JA, 'en-US' As EN, 'fr-FR' as FR, 'ar-SA' As AR)) Order By region;
select customer_id, metric_name, metric_value from MART.CUSTOMER_METRICS unpivot include nulls (metric_value For metric_name In (lifetime_value, order_count, support_ticket_count, loyalty_points)) Qualify ROW_NUMBER() Over (partition by customer_id, metric_name Order By metric_value Desc Nulls LAST) = 1;
